  async searchForCosigner() {
    if (this.cosignersForm.controls.search_input.value.length > 0) {
      if (this.cosignersForm.controls.search_type.value == 1) {
        this.showLoader = true;
        this.http
          .get<ClientInfo>(
            this.env.API_URL +
              `api/Clients/GetCoSignerByCode?clientCode=${this.cosignersForm.controls.search_input.value}`
          )
          .subscribe({
            next: async (data) => {
              console.log(data);
              if (data) {
                this.addCosignerRow(data);
              }
              this.showLoader = false;
            },
            error: async (err) => {
              console.log(err);
              await this.alertService.showAlertError(err.error, false);
              this.showLoader = false;
            },
          });
      } else {
        if (this.cosignersForm.controls.search_type.value == 2) {
          this.showLoader = true;
          this.http
            .get<ClientInfo>(
              this.env.API_URL +
                `api/Clients/GetCoSignerByNationID?nationID=${this.cosignersForm.controls.search_input.value}`
            )
            .subscribe({
              next: (data) => {
                this.addCosignerRow(data);
                this.showLoader = false;
              },
              error: async (err) => {
                console.log(err);
                await this.alertService.showAlertError(err.error, false);
                this.showLoader = false;
              },
            });
        } else {
          await this.alertService.showAlertError("يجب اختيار نوع بحث", false);
        }
      }
    } else {
      await this.alertService.showAlertError("يجب ادخال بحث", false);
    }
  }

