  addCosignerRow(cosigner: ClientInfo) {
    const duplicateCosignerIndex = this.cosignersData.findIndex((value) => {
      return (
        value.nation_id == cosigner.nation_id ||
        value.client_key == cosigner.client_key
      );
    });
    console.log(
      this.cosignersArray,
      this.cosignersData,
      duplicateCosignerIndex
    );
    if (duplicateCosignerIndex > -1) {
      return;
    }
    const cosignerForm = this.formBuilder.group({
      search_input: [
        this.cosignersForm.controls.search_input.value,
        [Validators.required],
      ],
      search_type: [
        this.cosignersForm.controls.search_type.value,
        [Validators.required],
      ],
      co_name: [cosigner.client_name, [Validators.required]],
      co_code: [
        cosigner.branch_code + "/" + cosigner.client_code,
        [Validators.required],
      ],
      co_gender: [cosigner.gender],
      co_nat_id: [cosigner.nation_id, [Validators.required]],
      co_id_date: [cosigner.id_date],
      co_birthdate: [cosigner.birth_date],
      co_telephone: [cosigner.mobile_1],
      co_address: [cosigner.home_add_1],
    });
    this.cosignersArray.push(cosignerForm);
    this.cosignersData.push(cosigner);
    console.log(this.cosignersArray, this.cosignersData);
  }
